@using RecipeHub.Services
@rendermode InteractiveServer
@inject RecipeService RecipeService

<div class="star-rating">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= _selectedRating ? "filled" : "")"
              @onclick="() => Rate(star)"
              title="Rate @star star(s)">
            @(star <= _selectedRating ? "★" : "☆")
        </span>
    }
    @if (_submitted)
    {
        <span class="rating-feedback ms-2 text-success">Thanks for rating!</span>
    }
</div>

<div class="average-rating text-muted small mt-1">
    @if (_averageRating > 0)
    {
        <span>Average: @_averageRating.ToString("F1") / 5 (@_ratingCount ratings)</span>
    }
    else
    {
        <span>No ratings yet — be the first!</span>
    }
</div>

@code {
    [Parameter] public int RecipeId { get; set; }

    private int _selectedRating;
    private bool _submitted;
    private double _averageRating;
    private int _ratingCount;

    protected override void OnInitialized()
    {
        RefreshRating();
    }

    private void Rate(int stars)
    {
        _selectedRating = stars;
        RecipeService.AddRating(RecipeId, stars);
        _submitted = true;
        RefreshRating();
    }

    private void RefreshRating()
    {
        var recipe = RecipeService.GetById(RecipeId);
        if (recipe is not null)
        {
            _averageRating = recipe.AverageRating;
            _ratingCount = recipe.RatingCount;
        }
    }
}

