using RecipeHub.Models;

namespace RecipeHub.Services;

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1, Title = "Classic Margherita Pizza", Category = "Italian",
            Description = "A simple and delicious pizza with fresh mozzarella and basil.",
            Ingredients = "Pizza dough\nSan Marzano tomatoes\nFresh mozzarella\nFresh basil\nOlive oil\nSalt",
            Steps = "1. Preheat oven to 475°F (245°C).\n2. Roll out dough on a floured surface.\n3. Spread crushed tomatoes over the dough.\n4. Tear mozzarella and distribute evenly.\n5. Bake for 10-12 minutes until crust is golden.\n6. Top with fresh basil and a drizzle of olive oil."
        },
        new Recipe
        {
            Id = 2, Title = "Spaghetti Carbonara", Category = "Italian",
            Description = "Creamy pasta with pancetta and Parmesan.",
            Ingredients = "Spaghetti\nPancetta\nEggs\nParmesan cheese\nBlack pepper\nSalt",
            Steps = "1. Cook spaghetti in salted boiling water.\n2. Fry pancetta until crispy.\n3. Whisk eggs with grated Parmesan and pepper.\n4. Toss hot pasta with pancetta.\n5. Remove from heat and stir in egg mixture.\n6. Serve immediately with extra Parmesan."
        },
        new Recipe
        {
            Id = 3, Title = "Chicken Tikka Masala", Category = "Indian",
            Description = "Tender chicken in a rich, spiced tomato sauce.",
            Ingredients = "Chicken breast\nYogurt\nGaram masala\nTurmeric\nCumin\nTomato sauce\nHeavy cream\nGarlic\nGinger\nOnion",
            Steps = "1. Marinate chicken in yogurt and spices for 2 hours.\n2. Grill or pan-fry chicken until charred.\n3. Sauté onion, garlic, and ginger.\n4. Add tomato sauce and spices, simmer 15 minutes.\n5. Add cream and cooked chicken.\n6. Simmer 10 more minutes. Serve with rice or naan."
        },
        new Recipe
        {
            Id = 4, Title = "Vegetable Pad Thai", Category = "Thai",
            Description = "A vibrant stir-fried noodle dish with crunchy vegetables.",
            Ingredients = "Rice noodles\nTofu\nBean sprouts\nCarrots\nGreen onions\nPeanuts\nLime\nFish sauce\nTamarind paste\nSugar\nChili flakes",
            Steps = "1. Soak rice noodles in warm water for 30 minutes.\n2. Press and cube tofu, then pan-fry until golden.\n3. Mix tamarind paste, fish sauce, sugar, and chili for the sauce.\n4. Stir-fry carrots and green onions.\n5. Add drained noodles and sauce, toss well.\n6. Top with bean sprouts, peanuts, and lime wedges."
        },
        new Recipe
        {
            Id = 5, Title = "Beef Tacos", Category = "Mexican",
            Description = "Seasoned ground beef in warm tortillas with fresh toppings.",
            Ingredients = "Ground beef\nTaco seasoning\nCorn tortillas\nLettuce\nTomato\nCheddar cheese\nSour cream\nSalsa",
            Steps = "1. Brown ground beef in a skillet.\n2. Add taco seasoning and water, simmer 5 minutes.\n3. Warm tortillas in a dry pan.\n4. Dice tomato and shred lettuce.\n5. Assemble tacos with meat, cheese, lettuce, tomato.\n6. Top with sour cream and salsa."
        },
        new Recipe
        {
            Id = 6, Title = "Miso Ramen", Category = "Japanese",
            Description = "A comforting bowl of ramen with rich miso broth.",
            Ingredients = "Ramen noodles\nMiso paste\nChicken broth\nSoft-boiled egg\nGreen onions\nCorn\nNori\nSesame oil\nSoy sauce\nGarlic",
            Steps = "1. Bring chicken broth to a simmer.\n2. Whisk in miso paste and soy sauce.\n3. Cook ramen noodles according to package.\n4. Prepare soft-boiled eggs (6.5 minutes).\n5. Assemble bowls: noodles, broth, halved egg.\n6. Top with corn, green onions, nori, and sesame oil."
        }
    };

    public IReadOnlyList<Recipe> GetAll() => _recipes.AsReadOnly();

    public IReadOnlyList<string> GetCategories() =>
        _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();

    public IReadOnlyList<Recipe> GetByCategory(string category) =>
        _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();

    public Recipe? GetById(int id) => _recipes.FirstOrDefault(r => r.Id == id);

    public void AddRating(int recipeId, int stars)
    {
        var recipe = GetById(recipeId);
        if (recipe is not null && stars >= 1 && stars <= 5)
        {
            recipe.TotalRating += stars;
            recipe.RatingCount++;
        }
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Count > 0 ? _recipes.Max(r => r.Id) + 1 : 1;
        _recipes.Add(recipe);
    }
}

