@page "/"
@using RecipeHub.Services
@inject RecipeService RecipeService

<PageTitle>RecipeHub - Recipe Sharing Community</PageTitle>

<div class="text-center mb-4">
    <h1>🍳 Welcome to RecipeHub</h1>
    <p class="lead">Discover, share, and rate delicious recipes from around the world.</p>
</div>

<h2>Browse by Category</h2>
<div class="row">
    @foreach (var category in RecipeService.GetCategories())
    {
        <div class="col-md-4 mb-3">
            <div class="card h-100">
                <div class="card-body text-center">
                    <h4 class="card-title">@GetCategoryEmoji(category) @category</h4>
                    <p class="card-text">@RecipeService.GetByCategory(category).Count recipe(s)</p>
                    <a href="category/@category" class="btn btn-primary">View Recipes</a>
                </div>
            </div>
        </div>
    }
</div>

<div class="mt-4 text-center">
    <a href="submit" class="btn btn-success btn-lg">📝 Submit a Recipe</a>
</div>

@code {
    private string GetCategoryEmoji(string category) => category switch
    {
        "Italian" => "🇮🇹",
        "Indian" => "🇮🇳",
        "Thai" => "🇹🇭",
        "Mexican" => "🇲🇽",
        "Japanese" => "🇯🇵",
        _ => "🍽️"
    };
}

