@page "/submit"
@rendermode InteractiveServer
@using RecipeHub.Models
@using RecipeHub.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation

<PageTitle>Submit a Recipe - RecipeHub</PageTitle>

<h1>📝 Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (_submitted)
{
    <div class="alert alert-success">
        <h4>Recipe Submitted!</h4>
        <p>Your recipe "<strong>@_model.Title</strong>" has been added successfully.</p>
        <a href="recipe/@_submittedId" class="btn btn-primary">View Your Recipe</a>
        <button class="btn btn-outline-secondary ms-2" @onclick="Reset">Submit Another</button>
    </div>
}
else
{
    <EditForm Model="_model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger" />

        <div class="mb-3">
            <label for="title" class="form-label">Recipe Title</label>
            <InputText id="title" class="form-control" @bind-Value="_model.Title" placeholder="e.g., Grandma's Apple Pie" />
            <ValidationMessage For="() => _model.Title" />
        </div>

        <div class="mb-3">
            <label for="category" class="form-label">Category</label>
            <InputSelect id="category" class="form-select" @bind-Value="_model.Category">
                <option value="">-- Select a category --</option>
                @foreach (var cat in RecipeService.GetCategories())
                {
                    <option value="@cat">@cat</option>
                }
                <option value="Other">Other</option>
            </InputSelect>
            <ValidationMessage For="() => _model.Category" />
        </div>

        <div class="mb-3">
            <label for="description" class="form-label">Short Description</label>
            <InputText id="description" class="form-control" @bind-Value="_model.Description" placeholder="A brief description of your recipe" />
        </div>

        <div class="mb-3">
            <label for="ingredients" class="form-label">Ingredients (one per line)</label>
            <InputTextArea id="ingredients" class="form-control" rows="6" @bind-Value="_model.Ingredients" placeholder="2 cups flour&#10;1 cup sugar&#10;3 eggs" />
            <ValidationMessage For="() => _model.Ingredients" />
        </div>

        <div class="mb-3">
            <label for="steps" class="form-label">Steps (one per line)</label>
            <InputTextArea id="steps" class="form-control" rows="6" @bind-Value="_model.Steps" placeholder="1. Preheat oven to 350°F&#10;2. Mix dry ingredients&#10;3. Add wet ingredients" />
            <ValidationMessage For="() => _model.Steps" />
        </div>

        <button type="submit" class="btn btn-success btn-lg">Submit Recipe</button>
    </EditForm>
}

@code {
    private RecipeFormModel _model = new();
    private bool _submitted;
    private int _submittedId;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = _model.Title,
            Category = _model.Category,
            Description = _model.Description,
            Ingredients = _model.Ingredients,
            Steps = _model.Steps
        };
        RecipeService.AddRecipe(recipe);
        _submittedId = recipe.Id;
        _submitted = true;
    }

    private void Reset()
    {
        _model = new();
        _submitted = false;
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required")]
        public string Category { get; set; } = string.Empty;

        public string Description { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Ingredients are required")]
        public string Ingredients { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Steps are required")]
        public string Steps { get; set; } = string.Empty;
    }
}

.star-rating .star {
    font-size: 1.5rem;
    cursor: pointer;
    transition: transform 0.1s;
}

.star-rating .star:hover {
    transform: scale(1.2);
}

.star-rating .star.filled {
    color: #ffc107;
}

